                        status = "disabled";
                };
        };

        otghs_fs_phy: otghs_fs_phy {
                compatible = "usb-nop-xceiv";
                #phy-cells = <0>;
        };
};

zephyr_udc0: &usbotg_hs {
        pinctrl-0 = <&usb_otg_hs_dm_pd7 &usb_otg_hs_dp_pd6>;
        pinctrl-names = "default";
        status = "okay";
};

&zephyr_udc0 {
        cdc_acm_uart0 {
                compatible = "zephyr,cdc-acm-uart";
                label = "Zephyr USB CDC-ACM";
        };
