zephyrproject-rtos/zephyr#98501.body:
### Describe the bug

1. PD_CLAIMED Not Set on First Usage in ISR-SAFE Context  
When calling pm_device_runtime_get() for a device that has never been used (usage == 0) and is marked as ISR_SAFE, the code checks the PD_CLAIMED flag to determine if the power domain should be resumed. However, PD_CLAIMED is not set on first usage, so the power domain's pm_device_runtime_get() is not called. This may result in the device being resumed without properly resuming its power domain, leading to incorrect power management behavior.

```c
static int get_sync_locked(const struct device *dev)
{
	int ret;
	struct pm_device_isr *pm = dev->pm_isr;
	uint32_t flags = pm->base.flags;

	if (pm->base.usage == 0) {
		if (flags & BIT(PM_DEVICE_FLAG_PD_CLAIMED)) {
			const struct device *domain = PM_DOMAIN(&pm->base);

			if (domain->pm_base->flags & BIT(PM_DEVICE_FLAG_ISR_SAFE)) {
				ret = pm_device_runtime_get(domain);
				if (ret < 0) {
					return ret;
				}
			} else {
				return -EWOULDBLOCK;
			}
		}

		ret = pm->base.action_cb(dev, PM_DEVICE_ACTION_RESUME);
		if (ret < 0) {
			return ret;
		}
		pm->base.state = PM_DEVICE_STATE_ACTIVE;
	} else {
		ret = 0;
	}

	pm->base.usage++;

	return ret;
}
``` 

2. PD_CLAIMED Not Cleared When Usage Reaches Zero in put_sync_locked()  
In the put_sync_locked() function, when usage reaches zero and the device is suspended, the code checks if PD_CLAIMED is set and, if so, recursively calls put_sync_locked() for the power domain. However, there is no logic to clear the PD_CLAIMED flag after releasing the power domain. This can cause the PD_CLAIMED flag to remain set even though the device is no longer using the power domain, resulting in incorrect power domain management and potential resource leaks.
```c
static int put_sync_locked(const struct device *dev)
{
	int ret;
	struct pm_device_isr *pm = dev->pm_isr;
	uint32_t flags = pm->base.flags;

	if (!(flags & BIT(PM_DEVICE_FLAG_RUNTIME_ENABLED))) {
		return 0;
	}

	if (pm->base.usage == 0U) {
		return -EALREADY;
	}

	pm->base.usage--;
	if (pm->base.usage == 0U) {
		ret = pm->base.action_cb(dev, PM_DEVICE_ACTION_SUSPEND);
		if (ret < 0) {
			pm->base.usage++;
			return ret;
		}
		pm->base.state = PM_DEVICE_STATE_SUSPENDED;

		if (flags & BIT(PM_DEVICE_FLAG_PD_CLAIMED)) {
			const struct device *domain = PM_DOMAIN(&pm->base);

			if (domain->pm_base->flags & BIT(PM_DEVICE_FLAG_ISR_SAFE)) {
				ret = put_sync_locked(domain);
			} else {
				ret = -EWOULDBLOCK;
			}
		}
	} else {
		ret = 0;
	}

	return ret;
}
``` 
